create or replace function public.register_inventory_device(p_branch_id uuid,p_brand text,p_model text,p_imei_1 text,p_imei_2 text,p_serial text,p_color text,p_storage text,p_ram text,p_cost numeric,p_cash_price numeric,p_mdm_compatible boolean default false)
returns uuid language plpgsql security definer set search_path='' as $$
declare v_org uuid;v_unit uuid;v_brand uuid;v_model uuid;v_id uuid;begin v_org=private.current_organization_id();if v_org is null or not private.has_permission('inventory.write')or not(private.has_branch_access(p_branch_id)or private.has_role('organization_owner')or private.has_role('organization_admin'))then raise exception'No autorizado'using errcode='42501';end if;if length(regexp_replace(p_imei_1,'[^0-9]','','g'))not in(14,15,16)or p_cost<0 or p_cash_price<=0 or p_cash_price<p_cost then raise exception'IMEI o precios inválidos';end if;select business_unit_id into v_unit from public.branches where id=p_branch_id and organization_id=v_org;insert into public.product_brands(organization_id,name)values(v_org,trim(p_brand))on conflict(organization_id,name)do update set status='active'returning id into v_brand;insert into public.product_models(organization_id,brand_id,name)values(v_org,v_brand,trim(p_model))on conflict(organization_id,brand_id,name)do update set status='active'returning id into v_model;insert into public.inventory_units(organization_id,owner_business_unit_id,current_branch_id,brand_id,model_id,imei_1,imei_2,serial_number,color,storage_capacity,ram_capacity,cost,cash_price,condition,mdm_compatible)values(v_org,v_unit,p_branch_id,v_brand,v_model,regexp_replace(p_imei_1,'[^0-9]','','g'),nullif(regexp_replace(p_imei_2,'[^0-9]','','g'),''),nullif(trim(p_serial),''),nullif(trim(p_color),''),nullif(trim(p_storage),''),nullif(trim(p_ram),''),p_cost,p_cash_price,'new',p_mdm_compatible)returning id into v_id;insert into public.inventory_unit_movements(organization_id,inventory_unit_id,to_branch_id,to_owner_business_unit_id,movement_type,actor_id)values(v_org,v_id,p_branch_id,v_unit,'initial_stock',auth.uid());return v_id;end$$;
revoke all on function public.register_inventory_device(uuid,text,text,text,text,text,text,text,text,numeric,numeric,boolean)from public,anon;grant execute on function public.register_inventory_device(uuid,text,text,text,text,text,text,text,text,numeric,numeric,boolean)to authenticated;
